pattern.example:
script {
    // Capture git diff
    def diffContent = sh(
        script: 'git diff origin/main...HEAD',
        returnStdout: true
    ).trim()

    // Build prompt with diff
    def prompt = """
Review the following code changes for security and quality issues:

${diffContent}

Focus on:
- SQL injection vulnerabilities
- Authentication/authorization issues
- Input validation
- Error handling
"""

    def analysis = askBob(prompt, 'solution-code-reviewer')
    echo analysis
}

script {
    // Test output already captured to file
    def testLog = readFile("${WORKSPACE}/test-output.log")

    def prompt = """
Analyze the following test failures and provide:
1. Root cause of each failure
2. Suggested fixes
3. Whether failures are related

Test Output:
${testLog}
"""

    def analysis = askBob(prompt, 'solution-test-failure-analyzer')
    echo analysis
}

script {
    // Gather various inputs
    def gitDiff = sh(script: 'git diff origin/main...HEAD', returnStdout: true).trim()
    def testResults = readFile("${WORKSPACE}/test-results.xml")
    def buildLog = readFile("${WORKSPACE}/build.log")

    def prompt = """
Perform a comprehensive analysis of this build:

=== CODE CHANGES ===
${gitDiff}

=== TEST RESULTS ===
${testResults}

=== BUILD LOG (last 100 lines) ===
${buildLog.split('\n').takeRight(100).join('\n')}

Provide:
1. Impact assessment of code changes
2. Test failure analysis
3. Build issue diagnosis
4. Recommendations for fixes
"""

    def analysis = askBob(prompt, 'solution-build-analyzer')
    echo analysis
}

script {
    // Read source files that changed
    def orderController = readFile("order-service/src/main/java/com/example/orders/controller/OrderController.java")
    def orderService = readFile("order-service/src/main/java/com/example/orders/service/OrderService.java")

    def prompt = """
Review these files for security vulnerabilities:

=== OrderController.java ===
${orderController}

=== OrderService.java ===
${orderService}

Focus on:
- Input validation
- SQL injection risks
- Authentication/authorization
- Sensitive data exposure
"""

    def analysis = askBob(prompt, 'solution-security-scanner')
    echo analysis
}

practice.example:
