pitfall.good:
// DO THIS - capture the analysis
def analysis = askBob(prompt, 'solution-code-reviewer')
echo analysis

// Read the file content first
def testLog = readFile("${WORKSPACE}/test.log")
def prompt = "Analyze: ${testLog}"
